/**
 * 兑换统计分析模块
 *
 * @file admin/src/modules/market/composables/exchange-stats.js
 * @description 兑换数据统计和图表展示
 * @version 1.0.0
 * @date 2026-01-24
 */

// ES Module 导入
import { logger } from '../../../utils/logger.js'
import { EXCHANGE_ENDPOINTS } from '../../../api/market/exchange.js'
import { request } from '../../../api/base.js'
import { loadECharts } from '../../../utils/echarts-lazy.js'

/**
 * 统计分析状态
 * @returns {Object} 状态对象
 */
export function useExchangeStatsState() {
  return {
    /**
     * 频道筛选标识（可选）：设为 'prop' 时统计仅道具商城（星石轨），
     * 不设置（undefined）时统计全兑换市场。由页面组件按需注入。
     * @type {string|undefined}
     */
    statsItemType: undefined,
    /** @type {Object} 兑换统计数据 */
    exchangeStats: {
      orders: { total: 0, pending: 0, completed: 0, shipped: 0, cancelled: 0 },
      revenue: { total_virtual_value: 0, total_points: 0 },
      items: { activeCount: 0, activeStock: 0, inactiveCount: 0, inactiveStock: 0 }
    },
    /** @type {Object|null} 订单状态分布图表实例 */
    orderStatusChart: null,
    /** @type {Object|null} 兑换趋势图表实例 */
    exchangeTrendChart: null,
    /** @type {Array} 趋势数据（来自 statistics.order_trend_by_day 或服务端聚合） */
    trendData: [],
    /** @type {Array<{date:string,order_count:number,revenue:number}>|null} 服务端按日趋势原始数据 */
    orderTrendByDay: null,
    /** @type {string} 趋势时间范围 */
    trendRange: '7d',
    /**
     * 履约追踪数据（由后端 GET /console/exchange/stats → fulfillment_tracking 字段返回）
     * 后端 ExchangeRecord 状态枚举：pending / completed / shipped / cancelled
     * @type {Object}
     */
    fulfillmentTracking: {
      total_orders: 0,
      pending_count: 0,
      shipped_count: 0,
      completed_count: 0,
      cancelled_count: 0,
      fulfillment_rate: 0,
      avg_fulfillment_time: 0 // 平均履约时间（小时）
    }
  }
}

/**
 * 统计分析方法
 * @returns {Object} 方法对象
 */
export function useExchangeStatsMethods() {
  return {
    /**
     * 加载兑换统计数据
     * 从商品列表 + 订单列表两个可用端点聚合统计
     */
    async loadExchangeStats() {
      try {
        this.loading = true
        /*
         * 频道筛选（道具商城/星石轨）：当组件设置了 this.statsItemType（如 'prop'）时，
         * 透传给后端 stats 接口做服务端聚合；兑换市场不设置该值，行为完全不变（全市场聚合）。
         */
        const params = {}
        if (this.statsItemType) params.item_type = this.statsItemType
        const statsRes = await request({
          url: EXCHANGE_ENDPOINTS.STATS,
          method: 'GET',
          params
        })

        if (!statsRes.success || !statsRes.data) {
          throw new Error(statsRes.message || '兑换统计数据为空')
        }

        const d = statsRes.data
        const os = d.orders_summary || {}
        const isu = d.items_summary || {}
        const ft = d.fulfillment_tracking || {}

        this.exchangeStats = {
          orders: {
            total: os.total ?? 0,
            pending: os.pending ?? 0,
            completed: os.completed ?? 0,
            shipped: os.shipped ?? 0,
            cancelled: os.cancelled ?? 0
          },
          revenue: {
            total_virtual_value: os.total_pay_amount ?? 0,
            total_points: os.total ?? 0
          },
          items: {
            activeCount: isu.active_count ?? 0,
            activeStock: isu.active_stock ?? 0,
            inactiveCount: isu.inactive_count ?? 0,
            inactiveStock: isu.inactive_stock ?? 0,
            lowStockCount: isu.low_stock_count ?? 0
          }
        }

        this.fulfillmentTracking = {
          total_orders: ft.total_orders ?? 0,
          pending_count: ft.pending_count ?? 0,
          shipped_count: ft.shipped_count ?? 0,
          completed_count: ft.completed_count ?? 0,
          cancelled_count: ft.cancelled_count ?? 0,
          fulfillment_rate: ft.fulfillment_rate ?? 0,
          avg_fulfillment_time: ft.avg_fulfillment_time ?? 0
        }

        this.orderTrendByDay = Array.isArray(d.order_trend_by_day) ? d.order_trend_by_day : null
      } catch (e) {
        logger.error('[ExchangeStats] 加载统计数据失败:', e)
        this.showError?.('加载统计数据失败')
      } finally {
        this.loading = false
      }
    },

    /**
     * 加载趋势数据
     * 使用后端 order_trend_by_day 服务端聚合数据，不再前端拉取订单聚合
     */
    async loadTrendData() {
      try {
        const now = new Date()
        let days = 7
        if (this.trendRange === '30d') days = 30
        else if (this.trendRange === '90d') days = 90

        const dateMap = new Map()
        for (let i = days - 1; i >= 0; i--) {
          const date = new Date(now)
          date.setDate(date.getDate() - i)
          const dateStr = date.toISOString().split('T')[0]
          dateMap.set(dateStr, { date: dateStr, order_count: 0, revenue: 0 })
        }

        if (this.orderTrendByDay && this.orderTrendByDay.length > 0) {
          this.orderTrendByDay.forEach(row => {
            const d = row.date
            if (dateMap.has(d)) {
              const cell = dateMap.get(d)
              cell.order_count = Number(row.order_count) || 0
              cell.revenue = Number(row.revenue) || 0
            }
          })
        }

        this.trendData = Array.from(dateMap.values())
        logger.info('[ExchangeStats] 趋势数据加载完成', {
          days,
          dataPoints: this.trendData.length,
          source: this.orderTrendByDay?.length ? 'server' : 'empty',
          totalOrders: this.trendData.reduce((sum, d) => sum + d.order_count, 0)
        })

        this.updateTrendChart()
      } catch (e) {
        logger.error('[ExchangeStats] 加载趋势数据失败:', e)
        this.trendData = []
        this.updateTrendChart()
      }
    },

    /**
     * 初始化图表
     */
    initCharts() {
      this.initOrderStatusChart()
      this.initTrendChart()
    },

    /**
     * 初始化订单状态分布图表
     */
    async initOrderStatusChart() {
      const container = document.getElementById('orderStatusChart')
      if (!container) return

      try {
        const echarts = await loadECharts()
        if (!echarts) {
          logger.warn('[ExchangeStats] ECharts 未加载')
          return
        }

        if (this.orderStatusChart) {
          this.orderStatusChart.dispose()
        }

        this.orderStatusChart = echarts.init(container)

        const { orders } = this.exchangeStats
        const option = {
          tooltip: { trigger: 'item', formatter: '{b}: {c} ({d}%)' },
          legend: { orient: 'vertical', left: 'left', top: 'middle' },
          series: [
            {
              name: '订单状态',
              type: 'pie',
              radius: ['40%', '70%'],
              avoidLabelOverlap: false,
              itemStyle: { borderRadius: 10, borderColor: '#fff', borderWidth: 2 },
              // 默认显示标签（不需要悬停）
              label: {
                show: true,
                position: 'outside',
                formatter: '{b}: {c}',
                fontSize: 12
              },
              emphasis: { label: { show: true, fontSize: 14, fontWeight: 'bold' } },
              labelLine: { show: true },
              data: [
                { value: orders.pending, name: '待发货', itemStyle: { color: '#ffc107' } },
                { value: orders.shipped, name: '已发货', itemStyle: { color: '#17a2b8' } },
                { value: orders.completed, name: '已完成', itemStyle: { color: '#28a745' } },
                { value: orders.cancelled, name: '已取消', itemStyle: { color: '#dc3545' } }
              ].filter(item => item.value > 0)
            }
          ]
        }

        this.orderStatusChart.setOption(option)

        // 响应式（命名引用以便清理）
        this._orderStatusResizeHandler = () => this.orderStatusChart?.resize()
        window.addEventListener('resize', this._orderStatusResizeHandler)
      } catch (e) {
        logger.error('[ExchangeStats] 初始化订单状态图表失败:', e)
      }
    },

    /**
     * 初始化兑换趋势图表
     */
    async initTrendChart() {
      const container = document.getElementById('exchangeTrendChart')
      if (!container) return

      try {
        const echarts = await loadECharts()
        if (!echarts) return

        if (this.exchangeTrendChart) {
          this.exchangeTrendChart.dispose()
        }

        this.exchangeTrendChart = echarts.init(container)

        // 加载趋势数据
        await this.loadTrendData()
      } catch (e) {
        logger.error('[ExchangeStats] 初始化趋势图表失败:', e)
      }
    },

    /**
     * 更新趋势图表
     */
    updateTrendChart() {
      if (!this.exchangeTrendChart) return

      // 格式化日期为 "MM-DD" 格式
      const dates = this.trendData.map(item => {
        const [, month, day] = item.date.split('-')
        return `${month}-${day}`
      })
      const orders = this.trendData.map(item => item.order_count || 0)
      const revenue = this.trendData.map(item => item.revenue || 0)

      // 计算最大值用于Y轴
      const maxOrders = Math.max(...orders, 1)
      const maxRevenue = Math.max(...revenue, 1)

      const option = {
        tooltip: {
          trigger: 'axis',
          axisPointer: { type: 'cross' },
          formatter: function (params) {
            let result = params[0].axisValue + '<br/>'
            params.forEach(p => {
              const unit = p.seriesName === '兑换金额' ? ' 积分' : ' 单'
              result += `${p.marker} ${p.seriesName}: ${p.value}${unit}<br/>`
            })
            return result
          }
        },
        legend: { data: ['订单数', '兑换金额'], top: 5 },
        grid: { left: '3%', right: '4%', bottom: '3%', top: 50, containLabel: true },
        xAxis: {
          type: 'category',
          boundaryGap: true,
          data: dates,
          axisLabel: {
            interval: this.trendRange === '7d' ? 0 : 'auto',
            fontSize: 11
          }
        },
        yAxis: [
          {
            type: 'value',
            name: '订单数',
            position: 'left',
            minInterval: 1,
            max: maxOrders < 5 ? 5 : null
          },
          {
            type: 'value',
            name: '金额',
            position: 'right',
            max: maxRevenue < 100 ? 100 : null
          }
        ],
        series: [
          {
            name: '订单数',
            type: 'line',
            smooth: true,
            data: orders,
            itemStyle: { color: '#5470c6' },
            areaStyle: { opacity: 0.2 },
            label: {
              show: orders.some(v => v > 0),
              position: 'top',
              fontSize: 10
            }
          },
          {
            name: '兑换金额',
            type: 'bar',
            yAxisIndex: 1,
            data: revenue,
            itemStyle: { color: '#91cc75' },
            barMaxWidth: 30,
            label: {
              show: revenue.some(v => v > 0),
              position: 'top',
              fontSize: 10
            }
          }
        ]
      }

      this.exchangeTrendChart.setOption(option)
    },

    /**
     * 切换趋势时间范围
     * @param {string} range - 时间范围 ('7d'|'30d'|'90d')
     */
    changeTrendRange(range) {
      this.trendRange = range
      this.loadTrendData()
    },

    /**
     * 获取履约率状态颜色
     * @param {number} rate - 履约率百分比
     * @returns {string} CSS类
     */
    getFulfillmentRateClass(rate) {
      if (rate >= 80) return 'text-green-600'
      if (rate >= 50) return 'text-yellow-600'
      return 'text-red-600'
    },

    /**
     * 获取履约率状态标签
     * @param {number} rate - 履约率百分比
     * @returns {string} 状态标签
     */
    getFulfillmentRateLabel(rate) {
      if (rate >= 80) return '✅ 优秀'
      if (rate >= 50) return '⚠️ 一般'
      return '🔴 需关注'
    },

    /**
     * 销毁图表实例
     */
    destroyCharts() {
      if (this.orderStatusChart) {
        this.orderStatusChart.dispose()
        this.orderStatusChart = null
      }
      if (this.exchangeTrendChart) {
        this.exchangeTrendChart.dispose()
        this.exchangeTrendChart = null
      }
    }
  }
}

export default { useExchangeStatsState, useExchangeStatsMethods }
